#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int MX=22010,N=2.5e5+10;const double Mod=1e9;
int pm[MX],cpt;bool vs[N];long double Fib[N];
inline void Init(int mx=250000)
{
	vs[1]=1;rep(2,mx,i)
	{
		if(!vs[i])pm[++cpt]=i;
		for(int j=1;j<=cpt&&pm[j]*i<=mx;++j)
		{
			vs[pm[j]*i]=1;if(i%pm[j]==0)break;
		}
	}
	bool flag=0;Fib[1]=1.0;Fib[2]=1.0;
	rep(3,mx,i)
	{
		Fib[i]=Fib[i-1];
		if(flag)Fib[i]+=Fib[i-2]/10.0;else Fib[i]+=Fib[i-2];flag=0;
		while(Fib[i]>Mod)Fib[i]/=10.0,flag=1;
	}
}
int main()
{
	Init();int n;while(scanf("%d",&n)!=EOF)
	{
		switch(n)
		{
			case 1: puts("2");break;
			case 2: puts("3");break;
			default: printf("%d\n",int(Fib[pm[n]]));
		}
	}
}
